using System;using System.Collections.Generic;using System.Linq;class A{static int W,H,cx,cy,px,py,sc;static bool rf;static List<int[]>C=new(),hist=new();static List<int[]>Filt(List<int[]>c,int px,int py,int cx,int cy,int h,int s){return c.Where(p=>{long dp=(long)(p[0]-px)*(p[0]-px)+(long)(p[1]-py)*(p[1]-py);long dc=(long)(p[0]-cx)*(p[0]-cx)+(long)(p[1]-cy)*(p[1]-cy);return h==0?dc<dp:h==1?dc>dp:s>1||dc==dp;}).ToList();}static void Main(){var p=Console.ReadLine().Split(' ');W=int.Parse(p[0]);H=int.Parse(p[1]);Console.ReadLine();p=Console.ReadLine().Split(' ');cx=int.Parse(p[0]);cy=int.Parse(p[1]);sc=1;while((long)((W+sc-1)/sc)*((H+sc-1)/sc)>62500)sc*=2;for(int y=0;y<H;y+=sc)for(int x=0;x<W;x+=sc)C.Add(new[]{Math.Min(x+sc/2,W-1),Math.Min(y+sc/2,H-1)});px=cx;py=cy;rf=sc==1;for(;;){var h=Console.ReadLine().Trim();int hi=h[0]=='W'?0:h[0]=='C'?1:2;if(h=="WARMER"||h=="COLDER"||h=="SAME"){hist.Add(new[]{px,py,cx,cy,hi});C=Filt(C,px,py,cx,cy,hi,sc);if(!rf&&C.Count<=3){var seen=new HashSet<long>();var exp=new List<int[]>();foreach(var q in C)for(int ny=q[1]-sc;ny<=q[1]+sc;ny++)for(int nx=q[0]-sc;nx<=q[0]+sc;nx++){int px2=Math.Max(0,Math.Min(W-1,nx)),py2=Math.Max(0,Math.Min(H-1,ny));long k=(long)py2*W+px2;if(seen.Add(k))exp.Add(new[]{px2,py2});}foreach(var hh in hist)exp=Filt(exp,hh[0],hh[1],hh[2],hh[3],hh[4],1);C=exp;sc=1;rf=true;}}px=cx;py=cy;if(C.Count<=1){if(C.Count==1){cx=C[0][0];cy=C[0][1];}}else if(C.Count<=80){int best=int.MaxValue,bx=cx,by=cy;foreach(var q in C){if(q[0]==cx&&q[1]==cy)continue;int w=0,c2=0;foreach(var a in C){long dp=(long)(a[0]-cx)*(a[0]-cx)+(long)(a[1]-cy)*(a[1]-cy);long dt=(long)(a[0]-q[0])*(a[0]-q[0])+(long)(a[1]-q[1])*(a[1]-q[1]);if(dt<dp)w++;else if(dt>dp)c2++;}int s=Math.Abs(w-c2);if(s<best){best=s;bx=q[0];by=q[1];}}cx=bx;cy=by;}else{long sx=0,sy=0;foreach(var q in C){sx+=q[0];sy+=q[1];}cx=(int)Math.Round((double)sx/C.Count);cy=(int)Math.Round((double)sy/C.Count);}if(cx==px&&cy==py&&C.Count>0){long md=-1;foreach(var q in C){long d=(long)(q[0]-cx)*(q[0]-cx)+(long)(q[1]-cy)*(q[1]-cy);if(d>md){md=d;cx=q[0];cy=q[1];}}}Console.WriteLine($"{cx} {cy}");Console.Out.Flush();}}}